import { WorkflowRuntime } from 'mastra/workflows';

const detectPIIInWorkflow = async (workflow: WorkflowRuntime) => {
  const piiPatterns = [
    /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
    /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g,
    /\b\d{3}-\d{2}-\d{4}\b/g
  ];

  workflow.on('step.completed', (step) => {
    const output = step.output as any;
    const text = JSON.stringify(output);
    const findings = piiPatterns
      .flatMap(pattern => [...text.matchAll(pattern)])
      .map(match => ({ type: 'PII', value: match[0], stepId: step.id }));

    if (findings.length > 0) {
      console.warn('PII detected:', findings);
      return { hasPII: true, findings };
    }
    return { hasPII: false };
  });
};

import { AgentRuntime } from 'mastra/agents';

const monitorAgentTools = (agent: AgentRuntime) => {
  agent.onToolCall(async (toolCall) => {
    const result = await toolCall.execute();
    const piiRegex = /(?:\b\w+@\w+\.\w+\b|\d{3}[\-\s]?\d{3}[\-\s]?\d{4}\b)/gi;

    const matches = result.output.match(piiRegex);
    if (matches) {
      console.error(`PII found in tool ${toolCall.tool.name}:`, matches);
      return {
        ...result,
        metadata: { piiDetected: true, piiCount: matches.length }
      };
    }
    return result;
  });
};

import { MemoryManager } from 'mastra/memory';

const scanMemoryContext = (memory: MemoryManager) => {
  memory.onRetrieve((context) => {
    const hasPII = checkForPII(context.content);
    if (hasPII) {
      console.warn('PII in memory context:', hasPII.matches);
      return {
        ...context,
        flagged: true,
        piiRisk: 'high'
      };
    }
    return context;
  });
};

const checkForPII = (text: string) => {
  const patterns = {
    email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
    ssn: /\d{3}-\d{2}-\d{4}/g,
    phone: /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g
  };
  const findings = Object.entries(patterns).map(([type, regex]) => ({
    type,
    matches: [...text.matchAll(regex)]
  })).filter(r => r.matches.length > 0);
  return { hasPII: findings.length > 0, findings };
};

