import { MiddlewareFn } from 'mastra/workflows';

const piiRedactionMiddleware: MiddlewareFn = async (input, next) => {
  const redactedInput = redactPII(input);
  const result = await next(redactedInput);
  const redactedOutput = redactPII(result);
  return redactedOutput;
};

const redactPII = (data: any): any => {
  if (typeof data === 'string') {
    return data
      .replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, '[EMAIL]')
      .replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, '[PHONE]')
      .replace(/\d{3}-\d{2}-\d{4}/g, '[SSN]');
  }
  if (data && typeof data === 'object') {
    const redacted: any = Array.isArray(data) ? [] : {};
    for (const [key, value] of Object.entries(data)) {
      redacted[key] = redactPII(value);
    }
    return redacted;
  }
  return data;
};

