import { Tool } from 'mastra/agents';

const createSafeTool = <T extends Tool>(tool: T): T => {
  const safeExecute = async (...args: any[]) => {
    const result = await tool.execute(...args);
    return {
      ...result,
      output: sanitizeToolOutput(result.output),
      safe: true
    };
  };

  return Object.assign(tool, { execute: safeExecute });
};

const sanitizeToolOutput = (output: any): any => {
  const PII_REPLACEMENTS = {
    email: '[EMAIL REDACTED]',
    phone: '[PHONE REDACTED]',
    ssn: '[SSN REDACTED]'
  };

  if (typeof output === 'string') {
    return Object.entries(PII_REPLACEMENTS).reduce((acc, [pattern, replacement]) => {
      const regex = new RegExp(pattern === 'email' 
        ? '\ [A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Z|a-z]{2,}\ '
        : pattern === 'phone' 
        ? '\\b\\d{3}[-.]?\\d{3}[-.]?\\d{4}\\b'
        : '\\d{3}-\\d{2}-\\d{4}', 'g');
      return acc.replace(regex, replacement);
    }, output);
  }
  return output;
};

import { MemoryManager } from 'mastra/memory';

const installPIIMemoryFilter = (memory: MemoryManager) => {
  const originalRetrieve = memory.retrieve.bind(memory);

  memory.retrieve = async (query: string, options?: any) => {
    const context = await originalRetrieve(query, options);
    const safeContext = filterPIIFromContext(context);

    // Log for audit
    if (safeContext.modified) {
      console.log('PII filtered from memory context');
    }

    return safeContext;
  };
};

const filterPIIFromContext = (context: any) => {
  const patterns = [
    { name: 'email', pattern: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g, replacement: '[EMAIL]' },
    { name: 'phone', pattern: /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, replacement: '[PHONE]' },
    { name: 'ssn', pattern: /\d{3}-\d{2}-\d{4}/g, replacement: '[SSN]' }
  ];

  let modified = false;
  const filterRecursive = (obj: any): any => {
    if (typeof obj === 'string') {
      let filtered = obj;
      patterns.forEach(({ pattern, replacement }) => {
        if (filtered.match(pattern)) {
          filtered = filtered.replace(pattern, replacement);
          modified = true;
        }
      });
      return filtered;
    }
    if (obj && typeof obj === 'object') {
      const filteredObj = Array.isArray(obj) ? [] : {};
      for (const [key, value] of Object.entries(obj)) {
        filteredObj[key] = filterRecursive(value);
      }
      return filteredObj;
    }
    return obj;
  };

  return {
    ...context,
    content: filterRecursive(context.content),
    metadata: { ...context.metadata, piiFiltered: modified }
  };
};

